import { create } from 'zustand';
import { subscribeWithSelector } from 'zustand/middleware';

type NotificationSlice = {
  notifications: Notification[];
  unreadCount: number;
  push: (n: Notification) => void;
  markRead: (id: string) => void;
};

type OrgSlice = {
  currentOrgId: string | null;
  setOrg: (id: string) => void;
};

type AppStore = NotificationSlice & OrgSlice;

export const useStore = create<AppStore>()(
  subscribeWithSelector((set) => ({
    notifications: [],
    unreadCount: 0,
    push: (n) =>
      set((s) => ({
        notifications: [n, ...s.notifications].slice(0, 100),
        unreadCount: s.unreadCount + 1,
      })),
    markRead: (id) =>
      set((s) => ({
        notifications: s.notifications.map((x) =>
          x.id === id ? { ...x, read: true } : x
        ),
        unreadCount: Math.max(0, s.unreadCount - 1),
      })),
    currentOrgId: null,
    setOrg: (id) => set({ currentOrgId: id }),
  }))
);

export function NotificationBadge() {
  const count = useStore((s) => s.unreadCount);
  return <span>{count}</span>;
}

import { createContext, useContext, useMemo, useState, useSyncExternalStore } from 'react';

function createSelectableContext<T>() {
  type Listener = () => void;
  const Ctx = createContext<{
    get: () => T;
    set: (v: T | ((prev: T) => T)) => void;
    subscribe: (l: Listener) => () => void;
  } | null>(null);

  function Provider({ initial, children }: { initial: T; children: React.ReactNode }) {
    const store = useMemo(() => {
      let value = initial;
      const listeners = new Set<Listener>();
      return {
        get: () => value,
        set: (next: T | ((prev: T) => T)) => {
          value = typeof next === 'function' ? (next as (p: T) => T)(value) : next;
          listeners.forEach((l) => l());
        },
        subscribe: (l: Listener) => {
          listeners.add(l);
          return () => listeners.delete(l);
        },
      };
    }, []);
    return <Ctx.Provider value={store}>{children}</Ctx.Provider>;
  }

  function useSelector<S>(selector: (s: T) => S): S {
    const store = useContext(Ctx);
    if (!store) throw new Error('Provider missing');
    return useSyncExternalStore(
      store.subscribe,
      () => selector(store.get()),
      () => selector(store.get())
    );
  }

  return { Provider, useSelector };
}

export const NotificationStore = createSelectableContext<{
  notifications: Notification[];
  unreadCount: number;
}>();

function useTable<T>(config: {
  data: T[];
  columns: ColumnDef<T>[];
  sortable?: boolean;
  selectable?: boolean;
}) {
  const [sort, setSort] = useState<SortState | null>(null);
  const [selection, setSelection] = useState<Set<string>>(new Set());

  const sortedData = useMemo(() => {
    if (!sort) return config.data;
    const col = config.columns.find((c) => c.id === sort.columnId);
    if (!col?.accessor) return config.data;
    return [...config.data].sort((a, b) => {
      const av = col.accessor!(a);
      const bv = col.accessor!(b);
      const dir = sort.dir === 'asc' ? 1 : -1;
      return av < bv ? -dir : av > bv ? dir : 0;
    });
  }, [config.data, config.columns, sort]);

  return {
    headers: config.columns.map((c) => ({
      id: c.id,
      label: c.label,
      sorted: sort?.columnId === c.id ? sort.dir : null,
      toggleSort: () =>
        setSort((s) =>
          s?.columnId === c.id
            ? s.dir === 'asc'
              ? { columnId: c.id, dir: 'desc' }
              : null
            : { columnId: c.id, dir: 'asc' }
        ),
    })),
    rows: sortedData.map((row, i) => ({
      key: (row as any).id ?? i,
      cells: config.columns.map((c) => ({
        id: c.id,
        value: c.accessor ? c.accessor(row) : '',
        render: c.render ? c.render(row) : null,
      })),
      selected: selection.has((row as any).id),
      toggleSelect: () =>
        setSelection((s) => {
          const next = new Set(s);
          const id = (row as any).id;
          next.has(id) ? next.delete(id) : next.add(id);
          return next;
        }),
    })),
  };
}

function UserAdminPage() {
  const { data } = useUsers();
  const table = useTable({
    data: data ?? [],
    columns: [
      { id: 'name', label: 'Name', accessor: (u) => u.name },
      { id: 'email', label: 'Email', accessor: (u) => u.email },
    ],
    sortable: true,
  });
  return (
    <table>
      <thead>
        <tr>
          {table.headers.map((h) => (
            <th key={h.id} onClick={h.toggleSort}>
              {h.label} {h.sorted}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {table.rows.map((r) => (
          <tr key={r.key}>
            {r.cells.map((c) => (
              <td key={c.id}>{c.render ?? String(c.value)}</td>
            ))}
          </tr>
        ))}
      </tbody>
    </table>
  );
}

function DataTable<T>({
  data,
  children,
  onSortChange,
}: {
  data: T[];
  children: React.ReactNode;
  onSortChange?: (s: SortState | null) => void;
}) {
  const [sort, setSort] = useState<SortState | null>(null);
  const ctx = useMemo(
    () => ({
      data,
      sort,
      setSort: (s: SortState | null) => {
        setSort(s);
        onSortChange?.(s);
      },
    }),
    [data, sort, onSortChange]
  );
  return <TableCtx.Provider value={ctx}><table>{children}</table></TableCtx.Provider>;
}

DataTable.Column = function Column<T>({
  id,
  label,
  accessor,
  render,
}: ColumnProps<T>) {
  return null;
};

DataTable.Body = function Body<T>() {
  const ctx = useContext(TableCtx);
  const columns = useColumnChildren();
  return (
    <tbody>
      {ctx!.data.map((row: any, i) => (
        <tr key={row.id ?? i}>
          {columns.map((c) => (
            <td key={c.id}>
              {c.render ? c.render(row) : String(c.accessor(row))}
            </td>
          ))}
        </tr>
      ))}
    </tbody>
  );
};

function UserAdminPage() {
  const { data } = useUsers();
  return (
    <DataTable data={data ?? []}>
      <DataTable.Column id="name" label="Name" accessor={(u) => u.name} />
      <DataTable.Column id="email" label="Email" accessor={(u) => u.email} />
      <DataTable.Body />
    </DataTable>
  );
}

import { useForm, useWatch } from 'react-hook-form';
import { useEffect } from 'react';

const DRAFT_KEY = 'onboarding-draft-v1';

function useFormDraft<T extends Record<string, any>>(form: ReturnType<typeof useForm<T>>) {
  useEffect(() => {
    const stored = localStorage.getItem(DRAFT_KEY);
    if (stored) {
      try {
        form.reset(JSON.parse(stored));
      } catch {
        // corrupt draft - ignore
      }
    }
  }, [form]);

  useEffect(() => {
    let timer: ReturnType<typeof setTimeout> | null = null;
    const sub = form.watch((values) => {
      if (timer) clearTimeout(timer);
      timer = setTimeout(() => {
        localStorage.setItem(DRAFT_KEY, JSON.stringify(values));
      }, 400);
    });
    return () => {
      sub.unsubscribe();
      if (timer) clearTimeout(timer);
    };
  }, [form]);
}

function OnboardingForm() {
  const form = useForm<Onboarding>({
    mode: 'onBlur',
    defaultValues: { businessName: '', ein: '', routing: '' },
  });
  useFormDraft(form);

  const businessType = useWatch({ control: form.control, name: 'businessType' });

  return (
    <form onSubmit={form.handleSubmit(submit)}>
      <input {...form.register('businessName', { required: true })} />
      {businessType === 'corp' && (
        <input {...form.register('ein', { required: true, pattern: /^\d{2}-\d{7}$/ })} />
      )}
      <button type="submit">Continue</button>
    </form>
  );
}

// Orchestrator state lives in a reducer context
type OrchestratorState = {
  step: number;
  draftSavedAt: number | null;
  crossStepErrors: Record<string, string>;
};

function useOnboardingOrchestrator(form: ReturnType<typeof useForm<Onboarding>>) {
  const [state, dispatch] = useReducer(reducer, {
    step: 0,
    draftSavedAt: null,
    crossStepErrors: {},
  });

  // Persist drafts to IDB (async, off main thread)
  useEffect(() => {
    let cancelled = false;
    const sub = form.watch((values) => {
      // Use idle callback to avoid jank
      requestIdleCallback(async () => {
        if (cancelled) return;
        await idb.set('draft', { values, step: state.step });
        dispatch({ type: 'DRAFT_SAVED', at: Date.now() });
      });
    });
    return () => {
      cancelled = true;
      sub.unsubscribe();
    };
  }, [form, state.step]);

  // Cross-step validation runs when step changes
  const goToStep = useCallback(
    async (target: number) => {
      const values = form.getValues();
      const errors = validateCrossStep(values, state.step, target);
      if (Object.keys(errors).length) {
        dispatch({ type: 'CROSS_STEP_ERROR', errors });
        return false;
      }
      dispatch({ type: 'GO_TO_STEP', step: target });
      return true;
    },
    [form, state.step]
  );

  return { state, goToStep };
}

import * as Y from 'yjs';
import { IndexeddbPersistence } from 'y-indexeddb';
import { WebsocketProvider } from 'y-websocket';
import { useEffect, useState, useSyncExternalStore } from 'react';

class DocumentSync {
  doc: Y.Doc;
  idb: IndexeddbPersistence;
  ws: WebsocketProvider;

  constructor(docId: string) {
    this.doc = new Y.Doc();
    this.idb = new IndexeddbPersistence(docId, this.doc);
    this.ws = new WebsocketProvider('wss://sync', docId, this.doc);
  }

  destroy() {
    this.ws.destroy();
    this.idb.destroy();
    this.doc.destroy();
  }
}

function useDocumentSection(sync: DocumentSync, sectionId: string) {
  const sections = sync.doc.getMap('sections');
  return useSyncExternalStore(
    (cb) => {
      const observer = () => cb();
      sections.observeDeep(observer);
      return () => sections.unobserveDeep(observer);
    },
    () => sections.get(sectionId)
  );
}

function DocEditor({ docId }: { docId: string }) {
  const [sync] = useState(() => new DocumentSync(docId));
  useEffect(() => () => sync.destroy(), [sync]);

  const section = useDocumentSection(sync, 'main');
  return <Editor section={section} />;
}

import { useQuery, useQueryClient } from '@tanstack/react-query';
import * as Y from 'yjs';
import { useEffect, useMemo } from 'react';

function useDocument(docId: string) {
  const queryClient = useQueryClient();

  const { data: initialDoc, isPending, error } = useQuery({
    queryKey: ['doc', docId],
    queryFn: () => fetch(`/api/docs/${docId}`).then((r) => r.json()),
    staleTime: Infinity, // Don't refetch - Yjs handles updates
  });

  const sync = useMemo(() => {
    if (!initialDoc) return null;
    const doc = new Y.Doc();
    Y.applyUpdate(doc, new Uint8Array(initialDoc.snapshot));
    return new DocumentSync(docId, doc);
  }, [initialDoc, docId]);

  useEffect(() => {
    if (!sync) return;
    // Hydrate query cache on Yjs changes for non-editing consumers
    const observer = () => {
      queryClient.setQueryData(['doc', docId, 'snapshot'], sync.serialize());
    };
    sync.doc.on('update', observer);
    return () => {
      sync.doc.off('update', observer);
      sync.destroy();
    };
  }, [sync, queryClient, docId]);

  return { sync, isPending, error };
}

