// stores/filters.ts - Zustand for client UI state
import { create } from 'zustand';
import { subscribeWithSelector } from 'zustand/middleware';

interface FilterState {
  dateRange: { start: Date; end: Date };
  segments: string[];
  setDateRange: (range: FilterState['dateRange']) => void;
  toggleSegment: (id: string) => void;
}

export const useFilters = create<FilterState>()(
  subscribeWithSelector((set) => ({
    dateRange: { start: new Date(), end: new Date() },
    segments: [],
    setDateRange: (dateRange) => set({ dateRange }),
    toggleSegment: (id) =>
      set((s) => ({
        segments: s.segments.includes(id)
          ? s.segments.filter((x) => x !== id)
          : [...s.segments, id],
      })),
  }))
);

// api/analytics.ts - RTK Query still owns server state
import { createApi, fetchBaseQuery } from '@reduxjs/toolkit/query/react';

export const analyticsApi = createApi({
  reducerPath: 'analytics',
  baseQuery: fetchBaseQuery({ baseUrl: '/api' }),
  tagTypes: ['Report'],
  endpoints: (b) => ({
    getReport: b.query<Report, { start: string; end: string; segments: string[] }>({
      query: (params) => ({ url: '/report', params }),
      providesTags: ['Report'],
    }),
  }),
});

// Bridge: subscribe Zustand changes to RTK Query invalidation
import { store } from './store';

useFilters.subscribe(
  (s) => ({ dateRange: s.dateRange, segments: s.segments }),
  () => {
    store.dispatch(analyticsApi.util.invalidateTags(['Report']));
  }
);

export function ReportView() {
  const filters = useFilters();
  const { data, isLoading } = analyticsApi.useGetReportQuery({
    start: filters.dateRange.start.toISOString(),
    end: filters.dateRange.end.toISOString(),
    segments: filters.segments,
  });
  if (isLoading) return <Spinner />;
  return <Chart data={data!} />;
}

import { createSlice, PayloadAction } from '@reduxjs/toolkit';

interface FilterState {
  dateRange: { start: string; end: string };
  segments: string[];
}

const initialState: FilterState = {
  dateRange: { start: new Date().toISOString(), end: new Date().toISOString() },
  segments: [],
};

const filtersSlice = createSlice({
  name: 'filters',
  initialState,
  reducers: {
    setDateRange(state, action: PayloadAction<FilterState['dateRange']>) {
      state.dateRange = action.payload;
    },
    toggleSegment(state, action: PayloadAction<string>) {
      const idx = state.segments.indexOf(action.payload);
      if (idx >= 0) state.segments.splice(idx, 1);
      else state.segments.push(action.payload);
    },
  },
});

export const { setDateRange, toggleSegment } = filtersSlice.actions;
export default filtersSlice.reducer;

export function ReportView() {
  const filters = useAppSelector((s) => s.filters);
  const { data } = useGetReportQuery(filters);
  return <Chart data={data!} />;
}

