interface DialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  title: string;
  description?: string;
  children: ReactNode;
}

export function Dialog({ open, onOpenChange, title, description, children }: DialogProps) {
  return (
    <RadixDialog.Root open={open} onOpenChange={onOpenChange}>
      <RadixDialog.Portal>
        <RadixDialog.Overlay className="fixed inset-0 bg-black/50" />
        <RadixDialog.Content className="fixed inset-1/2 -translate-1/2 bg-surface p-6 rounded-lg">
          <RadixDialog.Title>{title}</RadixDialog.Title>
          {description && <RadixDialog.Description>{description}</RadixDialog.Description>}
          {children}
        </RadixDialog.Content>
      </RadixDialog.Portal>
    </RadixDialog.Root>
  );
}

// dialog/useConfirm.tsx - imperative hook layer
import { createContext, useCallback, useContext, useState, ReactNode } from 'react';

interface ConfirmOptions {
  title: string;
  body: ReactNode;
  confirmLabel?: string;
  cancelLabel?: string;
  destructive?: boolean;
}

type Resolver = (value: boolean) => void;

const ConfirmCtx = createContext<((opts: ConfirmOptions) => Promise<boolean>) | null>(null);

export function DialogProvider({ children }: { children: ReactNode }) {
  const [state, setState] = useState<{ opts: ConfirmOptions; resolve: Resolver } | null>(null);

  const confirm = useCallback(
    (opts: ConfirmOptions) =>
      new Promise<boolean>((resolve) => {
        setState({ opts, resolve });
      }),
    []
  );

  const handle = (result: boolean) => {
    state?.resolve(result);
    setState(null);
  };

  return (
    <ConfirmCtx.Provider value={confirm}>
      {children}
      {state && (
        <Dialog
          open
          onOpenChange={(o) => !o && handle(false)}
          title={state.opts.title}
        >
          <div>{state.opts.body}</div>
          <div className="flex gap-2 mt-4">
            <button onClick={() => handle(false)}>
              {state.opts.cancelLabel ?? 'Cancel'}
            </button>
            <button
              onClick={() => handle(true)}
              className={state.opts.destructive ? 'bg-red-600' : 'bg-action-primary'}
            >
              {state.opts.confirmLabel ?? 'Confirm'}
            </button>
          </div>
        </Dialog>
      )}
    </ConfirmCtx.Provider>
  );
}

export function useConfirm() {
  const ctx = useContext(ConfirmCtx);
  if (!ctx) throw new Error('useConfirm requires DialogProvider');
  return ctx;
}

// Consumer code
function PayButton({ amount }: { amount: number }) {
  const confirm = useConfirm();
  return (
    <button
      onClick={async () => {
        const ok = await confirm({
          title: 'Confirm payment',
          body: <p>Send ${amount}?</p>,
          destructive: true,
        });
        if (ok) await pay(amount);
      }}
    >
      Pay
    </button>
  );
}

import { Dialog } from '@/components/Dialog';
import { useState } from 'react';

function PayButton({ amount }: { amount: number }) {
  const [showConfirm, setShowConfirm] = useState(false);
  const [isPaying, setIsPaying] = useState(false);

  const handleConfirm = async () => {
    setIsPaying(true);
    try {
      await pay(amount);
      setShowConfirm(false);
    } finally {
      setIsPaying(false);
    }
  };

  return (
    <>
      <button onClick={() => setShowConfirm(true)}>Pay</button>
      <Dialog
        open={showConfirm}
        onOpenChange={setShowConfirm}
        title="Confirm payment"
      >
        <p>Send ${amount}?</p>
        <div className="flex gap-2 mt-4">
          <button onClick={() => setShowConfirm(false)}>Cancel</button>
          <button onClick={handleConfirm} disabled={isPaying}>
            {isPaying ? 'Sending...' : 'Confirm'}
          </button>
        </div>
      </Dialog>
    </>
  );
}

import { z } from 'zod';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';

const intakeSchema = z.object({
  patient: z.object({
    name: z.string().min(1).max(100),
    dob: z.string().regex(/^\d{4}-\d{2}-\d{2}$/, 'Invalid date'),
    ssn: z.string().regex(/^\d{3}-\d{2}-\d{4}$/, 'Invalid SSN'),
  }),
  insurance: z.discriminatedUnion('type', [
    z.object({
      type: z.literal('medicare'),
      medicareId: z.string().regex(/^[A-Z\d]{5}-[A-Z\d]{4}$/, 'Invalid Medicare ID'),
    }),
    z.object({
      type: z.literal('private'),
      memberId: z.string().min(1),
      groupId: z.string().optional(),
    }),
  ]),
}).superRefine((data, ctx) => {
  const dob = new Date(data.patient.dob);
  const age = (Date.now() - dob.getTime()) / (1000 * 60 * 60 * 24 * 365.25);
  if (age < 18 && !data.patient.guardian) {
    ctx.addIssue({
      code: 'custom',
      path: ['patient', 'guardian'],
      message: 'Guardian required for patients under 18',
    });
  }
});

export type Intake = z.infer<typeof intakeSchema>;

// HIPAA: log error paths but never values
function scrubError(err: z.ZodError) {
  return err.issues.map((i) => ({
    path: i.path.join('.'),
    code: i.code,
    // CRITICAL: do not include i.input or actual rejected value
  }));
}

function IntakeForm() {
  const form = useForm<Intake>({
    resolver: zodResolver(intakeSchema),
  });

  return (
    <form
      onSubmit={form.handleSubmit(
        (data) => submit(data),
        (errors) => {
          datadogLogs.logger.warn('intake_validation_failed', {
            errors: scrubError(errors as unknown as z.ZodError),
          });
        }
      )}
    >
      <input {...form.register('patient.name')} />
