// Resolver for RHF
import { Resolver } from 'react-hook-form';
export const valibotResolver = <T extends v.GenericSchema>(
  schema: T
): Resolver<v.InferOutput<T>> => async (values) => {
  const result = v.safeParse(schema, values);
  if (result.success) return { values: result.output, errors: {} };
  const errors: Record<string, { type: string; message: string }> = {};
  for (const issue of result.issues) {
    const path = issue.path?.map((p) => p.key).join('.') ?? '';
    errors[path] = { type: 'validation', message: issue.message };
  }
  return { values: {}, errors: errors as any };
};

