'use client';
import { useInfiniteQuery } from '@tanstack/react-query';
import { useEffect, useRef } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';

interface Page {
  products: Product[];
  nextCursor: string | null;
}

export function CatalogList({
  initialPage,
  initialCursor,
}: {
  initialPage: Page;
  initialCursor?: string;
}) {
  const router = useRouter();
  const search = useSearchParams();

  const query = useInfiniteQuery({
    queryKey: ['catalog', search.toString()],
    queryFn: ({ pageParam }) =>
      fetch(`/api/catalog?cursor=${pageParam ?? ''}`).then((r) => r.json()) as Promise<Page>,
    initialPageParam: initialCursor,
    initialData: { pages: [initialPage], pageParams: [initialCursor] },
    getNextPageParam: (last) => last.nextCursor,
  });

  const allProducts = query.data?.pages.flatMap((p) => p.products) ?? [];

  // Analytics: fire product_viewed when card crosses viewport
  const observerRef = useRef<IntersectionObserver | null>(null);
  useEffect(() => {
    observerRef.current = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (entry.isIntersecting) {
            const id = entry.target.getAttribute('data-product-id');
            if (id) analytics.track('product_viewed', { productId: id });
            observerRef.current?.unobserve(entry.target);
          }
        }
      },
      { rootMargin: '0px', threshold: 0.5 }
    );
    return () => observerRef.current?.disconnect();
  }, []);

  const handleLoadMore = async () => {
    const result = await query.fetchNextPage();
    const lastCursor = result.data?.pages.at(-1)?.nextCursor;
    if (lastCursor) {
      // Update URL for shareability without re-render
      const params = new URLSearchParams(search.toString());
      params.set('cursor', lastCursor);
      window.history.replaceState(null, '', `?${params.toString()}`);
      analytics.track('catalog_chunk_viewed', { cursor: lastCursor });
    }
  };

  return (
    <>
      <ul className="grid grid-cols-2 md:grid-cols-4 gap-4">
        {allProducts.map((p) => (
          <li
            key={p.id}
            data-product-id={p.id}
            ref={(el) => el && observerRef.current?.observe(el)}
          >
            <ProductCard product={p} />
          </li>
        ))}
      </ul>
      {query.hasNextPage && (
        <button
          onClick={handleLoadMore}
          disabled={query.isFetchingNextPage}
          className="mx-auto block px-6 py-3 bg-action-primary text-white rounded"
        >
          {query.isFetchingNextPage ? 'Loading...' : 'Load more'}
        </button>
      )}
      {/* Keyboard escape hatch: jump to cursor */}
      <form
        onSubmit={(e) => {
          e.preventDefault();
          const target = new FormData(e.currentTarget).get('page');
          router.push(`/catalog?jumpTo=page-${target}`);
        }}
        className="mt-4"
      >
        <label>
          Jump to page <input type="number" name="page" min={1} />
        </label>
        <button type="submit">Go</button>
      </form>
    </>
  );
}

'use client';
import Link from 'next/link';
import { useSearchParams } from 'next/navigation';

export function CatalogPagination({
  page,
  totalPages,
}: {
  page: number;
  totalPages: number;
}) {
  const search = useSearchParams();
  const params = new URLSearchParams(search.toString());

  const linkFor = (p: number) => {
    params.set('page', String(p));
    return `/catalog?${params.toString()}`;
  };

  // Window of 5 pages around current
  const start = Math.max(1, page - 2);
  const end = Math.min(totalPages, page + 2);
  const pages: number[] = [];
  for (let i = start; i <= end; i++) pages.push(i);

  return (
    <nav aria-label="Pagination" className="flex gap-2 justify-center mt-6">
      {page > 1 && <Link href={linkFor(page - 1)}>Previous</Link>}
      {start > 1 && (
        <>
          <Link href={linkFor(1)}>1</Link>
          {start > 2 && <span>...</span>}
        </>
      )}
      {pages.map((p) => (
        <Link
          key={p}
          href={linkFor(p)}
          aria-current={p === page ? 'page' : undefined}
          className={p === page ? 'font-bold' : ''}
        >
          {p}
        </Link>
      ))}
      {end < totalPages && (
        <>
          {end < totalPages - 1 && <span>...</span>}
          <Link href={linkFor(totalPages)}>{totalPages}</Link>
        </>
      )}
      {page < totalPages && <Link href={linkFor(page + 1)}>Next</Link>}
    </nav>
  );
}

// theme/ThemeProvider.tsx - runtime theme injection
import { useEffect, useState, createContext, useContext, ReactNode } from 'react';
import chroma from 'chroma-js';

interface TenantTheme {
  colors: {
    primary: string;
    surface: string;
    text: string;
  };
  fonts: { sans: string; mono: string };
  fontFaces: Array<{ family: string; url: string; weight: number }>;
  logoUrl: string;
  contrastTarget: 'AA' | 'AAA';
}

const ThemeCtx = createContext<TenantTheme | null>(null);

function applyTheme(theme: TenantTheme) {
  const root = document.documentElement;
  root.style.setProperty('--color-primary', theme.colors.primary);
  root.style.setProperty('--color-surface', theme.colors.surface);
  root.style.setProperty('--color-text', theme.colors.text);
  root.style.setProperty('--font-sans', theme.fonts.sans);

  // Defensive: log if contrast doesn't meet target
  const target = theme.contrastTarget === 'AAA' ? 7 : 4.5;
  const ratio = chroma.contrast(theme.colors.text, theme.colors.surface);
  if (ratio < target) {
    console.error('[theme] contrast violation', { ratio, target });
    // Could also report to Sentry/Datadog
  }
}

async function loadFonts(faces: TenantTheme['fontFaces']) {
  await Promise.all(
    faces.map(async ({ family, url, weight }) => {
      const face = new FontFace(family, `url(${url})`, { weight: String(weight) });
      await face.load();
      document.fonts.add(face);
    })
  );
}

export function ThemeProvider({
  tenantId,
  children,
}: {
  tenantId: string;
  children: ReactNode;
}) {
  const [theme, setTheme] = useState<TenantTheme | null>(null);

  useEffect(() => {
    let cancelled = false;
    fetch(`/api/tenants/${tenantId}/theme`)
      .then((r) => r.json() as Promise<TenantTheme>)
      .then(async (t) => {
        if (cancelled) return;
        await loadFonts(t.fontFaces);
        applyTheme(t);
        setTheme(t);
      });
    return () => {
      cancelled = true;
    };
  }, [tenantId]);

  if (!theme) return <div className="min-h-screen" />; // blank to avoid FOUC
  return <ThemeCtx.Provider value={theme}>{children}</ThemeCtx.Provider>;
}

export const useTheme = () => {
  const ctx = useContext(ThemeCtx);
  if (!ctx) throw new Error('useTheme outside ThemeProvider');
  return ctx;
};

