import { useTransition, startTransition, useOptimistic } from 'react';

export function KanbanBoard({ initialColumns }: { initialColumns: Column[] }) {
  const [columns, setColumns] = useState(initialColumns);

  const reorderColumns = (from: number, to: number) => {
    const next = [...columns];
    const [moved] = next.splice(from, 1);
    next.splice(to, 0, moved);

    // View Transitions API with fallback
    if (document.startViewTransition) {
      document.startViewTransition(() => {
        flushSync(() => setColumns(next));
      });
    } else {
      setColumns(next);
    }
  };

  return (
    <div className="flex gap-4">
      {columns.map((col, i) => (
        <div
          key={col.id}
          style={{ viewTransitionName: `column-${col.id}` } as React.CSSProperties}
          className="w-72 bg-surface p-3 rounded"
        >
