// kanban/Card.tsx - drag-drop with WAAPI for drop landing
import { useRef } from 'react';

export function Card({ card }: { card: CardType }) {
  const ref = useRef<HTMLDivElement>(null);
  const dragState = useRef<{ startX: number; startY: number } | null>(null);

  const handlePointerDown = (e: React.PointerEvent) => {
    dragState.current = { startX: e.clientX, startY: e.clientY };
    ref.current?.setPointerCapture(e.pointerId);
    ref.current?.style.setProperty('z-index', '10');
  };

  const handlePointerMove = (e: React.PointerEvent) => {
    if (!dragState.current || !ref.current) return;
    const dx = e.clientX - dragState.current.startX;
    const dy = e.clientY - dragState.current.startY;
    // Compositor-driven: transform only
    ref.current.style.transform = `translate(${dx}px, ${dy}px)`;
  };

  const handlePointerUp = (e: React.PointerEvent) => {
    if (!ref.current) return;
    dragState.current = null;
    // WAAPI animate-back if not over drop zone
    ref.current.animate(
      [{ transform: ref.current.style.transform }, { transform: 'translate(0, 0)' }],
      { duration: 200, easing: 'ease-out', fill: 'forwards' }
    ).addEventListener('finish', () => {
      ref.current!.style.transform = '';
      ref.current!.style.removeProperty('z-index');
    });
  };

  return (
    <div
      ref={ref}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      className="p-3 bg-white rounded shadow mb-2 cursor-grab touch-none"
    >
      {card.title}
    </div>
  );
}

