import { execSync } from 'child_process';
import fs from 'fs';

const BASELINE = 3200; // current error count after enabling flags

let output: string;
try {
  output = execSync('tsc --noEmit', { encoding: 'utf8' });
} catch (e: any) {
  output = e.stdout;
}

const errorCount = (output.match(/error TS\d+/g) ?? []).length;
console.log(`Type errors: ${errorCount} (baseline: ${BASELINE})`);

if (errorCount > BASELINE) {
  console.error(`Regression: ${errorCount - BASELINE} new type errors`);
  process.exit(1);
}

if (errorCount < BASELINE) {
  console.log(`Progress: ${BASELINE - errorCount} errors fixed. Update BASELINE to ${errorCount}.`);
  fs.writeFileSync('.tsc-baseline', String(errorCount));
}

