// components/SafeBoundary.tsx - per-subtree boundary with severity
import { Component, ReactNode, ErrorInfo } from 'react';
import { Activity } from 'react';
import * as Sentry from '@sentry/nextjs';

type Severity = 'critical' | 'degraded' | 'cosmetic';
type Mode = 'error' | 'hidden' | 'stale';

interface Props {
  feature: string;
  severity: Severity;
  fallbackMode: Mode;
  staleContent?: ReactNode;
  children: ReactNode;
}

interface State {
  hasError: boolean;
  errorCount: number;
  lastErrorAt: number;
}

export class SafeBoundary extends Component<Props, State> {
  state: State = { hasError: false, errorCount: 0, lastErrorAt: 0 };

  static getDerivedStateFromError(): Partial<State> {
    return { hasError: true };
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    const now = Date.now();
    const isSticky = now - this.state.lastErrorAt < 30_000;
    const errorCount = isSticky ? this.state.errorCount + 1 : 1;

    this.setState({ errorCount, lastErrorAt: now });

    Sentry.captureException(error, {
      tags: {
        severity: this.props.severity,
        feature: this.props.feature,
        sticky: String(isSticky),
        mode: this.props.fallbackMode,
      },
      contexts: { react: { componentStack: info.componentStack } },
    });

    // Auto-recover from first error after 2s (transient bug)
    if (errorCount === 1) {
      setTimeout(() => {
        this.setState({ hasError: false });
      }, 2000);
    }
  }

  render() {
    if (!this.state.hasError) return this.props.children;

    if (this.state.errorCount >= 2) {
      // Sticky failure - show explicit error UI
      return this.renderErrorUI();
    }

    // First-pass fallback by mode
    switch (this.props.fallbackMode) {
      case 'hidden':
        return (
          <Activity mode="hidden">{this.props.children}</Activity>
        );
      case 'stale':
        return this.props.staleContent ?? null;
      case 'error':
      default:
        return this.renderErrorUI();
    }
  }

  private renderErrorUI() {
    const { severity, feature } = this.props;
    if (severity === 'cosmetic') return null;
    return (
      <div role="alert" className="p-4 bg-red-50 rounded">
        <p>{feature} unavailable</p>
        {severity === 'critical' && (
          <button onClick={() => this.setState({ hasError: false, errorCount: 0 })}>
            Retry
          </button>
        )}
      </div>
    );
  }
}

// Usage
function Dashboard() {
  return (
    <div>
      <SafeBoundary feature="chart" severity="degraded" fallbackMode="stale" staleContent={<CachedChart />}>
        <LiveChart />
      </SafeBoundary>

      <SafeBoundary feature="third-party-widget" severity="cosmetic" fallbackMode="hidden">
        <ThirdPartyEmbed />
      </SafeBoundary>

      <SafeBoundary feature="payment-form" severity="critical" fallbackMode="error">
        <PaymentForm />
