// components/SmartLink.tsx - preload on hover/visibility/touch
import { Link, LinkProps } from 'react-router-dom';
import { useEffect, useRef } from 'react';

const preloaded = new Set<string>();

async function preloadRoute(path: string) {
  if (preloaded.has(path)) return;
  preloaded.add(path);
  // Match the dynamic import for the route
  if (path.startsWith('/dashboard')) await import('./pages/Dashboard');
  else if (path.startsWith('/editor')) await import('./pages/Editor');
  // ... or use a route -> import map
}

export function SmartLink({ to, ...props }: LinkProps & { to: string }) {
  const ref = useRef<HTMLAnchorElement>(null);

  useEffect(() => {
    if (!ref.current) return;
    // Visibility-based preload (mobile-friendly)
    const io = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          preloadRoute(to);
          io.disconnect();
        }
      },
      { rootMargin: '200px' }
    );
    io.observe(ref.current);
    return () => io.disconnect();
  }, [to]);

  return (
    <Link
      ref={ref}
      to={to}
      onMouseEnter={() => preloadRoute(to)}
      onTouchStart={() => preloadRoute(to)}
      onFocus={() => preloadRoute(to)}
      {...props}
    />
  );
}

