import { execSync } from 'child_process';
import fs from 'fs';
import path from 'path';

const BUDGETS = {
  'index': 200 * 1024,        // main bundle gzipped
  'editor': 120 * 1024,
  'chart-libs': 75 * 1024,
  'admin': 45 * 1024,
};

const dist = fs.readdirSync('dist/assets');
for (const [name, budget] of Object.entries(BUDGETS)) {
  const match = dist.find((f) => f.startsWith(name) && f.endsWith('.js.gz'));
  if (!match) continue;
  const size = fs.statSync(path.join('dist/assets', match)).size;
  if (size > budget) {
    console.error(`${name} exceeds budget: ${size} > ${budget}`);
    process.exit(1);
  }
}

