// hooks/useWorkflow.ts - shared state
export function useWorkflow() {
  const [workflow, setWorkflow] = useState<Workflow>({ nodes: [], edges: [] });
  const [mode, setMode] = useState<'canvas' | 'structured'>('canvas');
