}

// components/Canvas.tsx - keyboard-accessible canvas
export function WorkflowCanvas() {
  const { workflow, focusedNodeId, setFocusedNodeId } = useWorkflowContext();
  const announceRef = useRef<HTMLDivElement>(null);

  const announce = (msg: string) => {
    if (announceRef.current) announceRef.current.textContent = msg;
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Tab') return; // let browser handle focus order
    const current = workflow.nodes.find((n) => n.id === focusedNodeId);
    if (!current) return;

    if (e.key === 'ArrowRight') {
      // Navigate to the node closest in +x direction
      const next = nearestInDirection(workflow.nodes, current, 'right');
      if (next) {
        setFocusedNodeId(next.id);
        announce(`Focused ${next.label}, ${describeConnections(workflow, next)}`);
      }
      e.preventDefault();
    }
    if (e.key === 'Enter') {
      // Open node config
      openNodeEditor(current.id);
    }
    if (e.key === 'c' && e.ctrlKey) {
      // Connect mode: next node selection becomes connection target
      enterConnectMode(current.id);
      announce('Connect mode: select target node and press Enter');
    }
  };

  return (
    <>
      {/* Visually hidden live region */}
      <div
        ref={announceRef}
        role="status"
        aria-live="polite"
        className="sr-only"
      />
      <div
        role="application"
        aria-label="Workflow canvas"
        aria-describedby="canvas-instructions"
        tabIndex={0}
        onKeyDown={handleKeyDown}
        className="relative w-full h-screen bg-surface"
      >
        <p id="canvas-instructions" className="sr-only">
          Use arrow keys to navigate nodes. Enter to configure. Ctrl+C to connect.
        </p>
        {workflow.nodes.map((node) => (
          <div
            key={node.id}
            role="button"
            tabIndex={focusedNodeId === node.id ? 0 : -1}
            aria-label={`${node.label}, ${node.type}`}
            aria-describedby={`node-${node.id}-connections`}
            style={{ left: node.position.x, top: node.position.y }}
            className={`absolute p-3 rounded border-2 ${
              focusedNodeId === node.id ? 'border-action-primary' : 'border-gray-300'
            }`}
          >
            {node.label}
            <span id={`node-${node.id}-connections`} className="sr-only">
              {describeConnections(workflow, node)}
            </span>
          </div>
        ))}
      </div>
    </>
  );
}

function describeConnections(workflow: Workflow, node: WorkflowNode): string {
  const outgoing = workflow.edges.filter((e) => e.from === node.id);
  const incoming = workflow.edges.filter((e) => e.to === node.id);
  const parts: string[] = [];
  if (incoming.length) {
    parts.push(
      `incoming from ${incoming
        .map((e) => workflow.nodes.find((n) => n.id === e.from)?.label)
        .join(', ')}`
    );
  }
  if (outgoing.length) {
    parts.push(
      `outgoing to ${outgoing
        .map((e) => workflow.nodes.find((n) => n.id === e.to)?.label)
        .join(', ')}`
    );
  }
  return parts.length ? parts.join('; ') : 'no connections';
}

