// app/actions/cart.ts - Server Action
'use server';
import { z } from 'zod';
import { revalidatePath } from 'next/cache';

const addToCartSchema = z.object({
  productId: z.string().uuid(),
  quantity: z.number().int().min(1).max(99),
});

export async function addToCart(input: z.infer<typeof addToCartSchema>) {
  const parsed = addToCartSchema.parse(input);
  const session = await getSession();
  if (!session) throw new Error('Unauthorized');

  // Server: validate inventory, apply business rules
  const result = await db.transaction(async (tx) => {
    const inventory = await tx.inventory.findUnique({
      where: { productId: parsed.productId },
    });
    if (!inventory || inventory.available < parsed.quantity) {
      throw new Error('Insufficient inventory');
    }
    const cart = await tx.cart.upsert({
      where: { userId: session.userId },
      create: {
        userId: session.userId,
        items: { create: [{ productId: parsed.productId, quantity: parsed.quantity }] },
      },
      update: {
        items: {
          upsert: {
            where: { cartId_productId: { cartId: session.cartId, productId: parsed.productId } },
            create: { productId: parsed.productId, quantity: parsed.quantity },
            update: { quantity: { increment: parsed.quantity } },
          },
        },
      },
      include: { items: { include: { product: true } } },
    });
    return cart;
  });

  revalidatePath('/cart');
  return result;
}

// hooks/useCart.ts - React Query with optimistic
import { useMutation, useQuery, useQueryClient } from '@tanstack/react-query';
import { addToCart } from '@/app/actions/cart';

interface Cart {
  items: Array<{ productId: string; quantity: number; product: { name: string; price: number } }>;
  subtotal: number;
  discountCode?: string;
  discountAmount: number;
}

export function useCart() {
  return useQuery<Cart>({
    queryKey: ['cart'],
    queryFn: () => fetch('/api/cart').then((r) => r.json()),
  });
}

export function useAddToCart() {
  const qc = useQueryClient();

  return useMutation({
    mutationFn: addToCart,
    onMutate: async (variables) => {
      // Cancel in-flight refetches that might trample optimistic state
      await qc.cancelQueries({ queryKey: ['cart'] });
      const previousCart = qc.getQueryData<Cart>(['cart']);
      // Optimistically update
      qc.setQueryData<Cart>(['cart'], (old) => {
        if (!old) return old;
        const existingIdx = old.items.findIndex((i) => i.productId === variables.productId);
        let newItems;
        if (existingIdx >= 0) {
          newItems = old.items.map((i, idx) =>
            idx === existingIdx ? { ...i, quantity: i.quantity + variables.quantity } : i
          );
        } else {
          // We don't know the product price client-side - fetch from local cache or skip subtotal update
          newItems = [
            ...old.items,
            {
              productId: variables.productId,
              quantity: variables.quantity,
              product: { name: 'Loading...', price: 0 },
            },
          ];
        }
        return {
          ...old,
          items: newItems,
          // Discount stays - server will recompute. Compliance: don't extrapolate.
        };
      });
      return { previousCart };
    },
    onError: (err, _vars, context) => {
      // Rollback - critical for compliance (no stale discounts shown)
      if (context?.previousCart) {
        qc.setQueryData(['cart'], context.previousCart);
      }
      toast.error('Could not add to cart: ' + err.message);
    },
    onSuccess: (serverCart) => {
      qc.setQueryData(['cart'], serverCart);
    },
    onSettled: () => {
      // Always refetch authoritative state
      qc.invalidateQueries({ queryKey: ['cart'] });
    },
  });
}

// components/AddToCartButton.tsx
export function AddToCartButton({ productId }: { productId: string }) {
  const { mutate, isPending } = useAddToCart();
  return (
    <button
      onClick={() => mutate({ productId, quantity: 1 })}
      disabled={isPending}
    >
      {isPending ? 'Adding...' : 'Add to cart'}
    </button>
  );
}

'use client';
import { useOptimistic, useTransition } from 'react';
import { markAsRead } from './actions';

interface Notification {
  id: string;
  message: string;
  read: boolean;
}

export function NotificationList({ notifications }: { notifications: Notification[] }) {
  const [isPending, startTransition] = useTransition();
  const [optimisticNotifs, setOptimisticNotifs] = useOptimistic(
    notifications,
    (state, id: string) =>
      state.map((n) => (n.id === id ? { ...n, read: true } : n))
  );

  const handleRead = (id: string) => {
    startTransition(async () => {
      setOptimisticNotifs(id);
      await markAsRead(id);
    });
  };

  return (
    <ul>
      {optimisticNotifs.map((n) => (
        <li key={n.id} className={n.read ? 'opacity-50' : ''}>
          {n.message}
          {!n.read && <button onClick={() => handleRead(n.id)}>Mark read</button>}
        </li>
      ))}
    </ul>
  );
}

// FormField.tsx
import {
  createContext,
  forwardRef,
  useContext,
  useId,
  HTMLAttributes,
  InputHTMLAttributes,
  LabelHTMLAttributes,
  Children,
  ReactNode,
} from 'react';
import { cn } from './utils';

interface FieldContextValue {
  id: string;
  descriptionId: string;
  errorId: string;
  hasError: boolean;
  isRequired: boolean;
}

const FieldContext = createContext<FieldContextValue | null>(null);

function useFieldContext(): FieldContextValue {
  const ctx = useContext(FieldContext);
  if (!ctx) throw new Error('FormField primitives must be used inside FormField');
  return ctx;
}

interface FormFieldRootProps extends HTMLAttributes<HTMLDivElement> {
  error?: string;
  required?: boolean;
  children: ReactNode;
}

function FormFieldRoot({ error, required, children, className, ...rest }: FormFieldRootProps) {
  const id = useId();
  const descriptionId = `${id}-description`;
  const errorId = `${id}-error`;

  // Dev-mode warning if no Label child
  if (process.env.NODE_ENV !== 'production') {
    const childrenArr = Children.toArray(children);
    const hasLabel = childrenArr.some((c: any) => c?.type?.displayName === 'FormField.Label');
    if (!hasLabel) {
      console.warn('FormField requires a FormField.Label child for accessibility');
    }
  }

  return (
    <FieldContext.Provider
      value={{ id, descriptionId, errorId, hasError: !!error, isRequired: !!required }}
    >
      <div className={cn('flex flex-col gap-1', className)} {...rest}>
        {children}
        {error && (
          <p id={errorId} role="alert" className="text-red-600 text-sm">
            {error}
          </p>
        )}
      </div>
    </FieldContext.Provider>
  );
}

function Label({ children, className, ...rest }: LabelHTMLAttributes<HTMLLabelElement>) {
  const { id, isRequired } = useFieldContext();
  return (
    <label htmlFor={id} className={cn('text-sm font-medium', className)} {...rest}>
      {children}
      {isRequired && <span aria-label="required" className="text-red-600 ml-0.5">*</span>}
    </label>
  );
}
Label.displayName = 'FormField.Label';

function Description({ children, className, ...rest }: HTMLAttributes<HTMLParagraphElement>) {
  const { descriptionId } = useFieldContext();
  return (
    <p id={descriptionId} className={cn('text-sm text-muted', className)} {...rest}>
      {children}
    </p>
  );
}
Description.displayName = 'FormField.Description';

const Input = forwardRef<HTMLInputElement, InputHTMLAttributes<HTMLInputElement>>(
  ({ className, ...rest }, ref) => {
    const { id, descriptionId, errorId, hasError, isRequired } = useFieldContext();
    return (
      <input
        ref={ref}
        id={id}
        aria-describedby={cn(descriptionId, hasError && errorId)}
        aria-invalid={hasError || undefined}
        aria-required={isRequired || undefined}
        className={cn(
          'rounded border px-3 py-2',
          hasError ? 'border-red-600' : 'border-gray-300',
          className
        )}
        {...rest}
      />
    );
  }
);
Input.displayName = 'FormField.Input';

// Sugar for 80% case
function Simple({
  label,
  description,
  error,
  required,
  ...inputProps
}: {
  label: string;
  description?: string;
  error?: string;
  required?: boolean;
} & InputHTMLAttributes<HTMLInputElement>) {
  return (
    <FormFieldRoot error={error} required={required}>
      <Label>{label}</Label>
      {description && <Description>{description}</Description>}
      <Input {...inputProps} />
    </FormFieldRoot>
  );
}
Simple.displayName = 'FormField.Simple';

export const FormField = Object.assign(FormFieldRoot, {
  Label,
  Description,
  Input,
  Simple,
});

// Usage: simple case
