interface FormFieldProps extends InputHTMLAttributes<HTMLInputElement> {
  label: string;
  description?: string;
  error?: string;
  required?: boolean;
  helpTooltip?: string;
}

export const FormField = forwardRef<HTMLInputElement, FormFieldProps>(
  ({ label, description, error, required, helpTooltip, ...inputProps }, ref) => {
    const id = useId();
    const descId = `${id}-desc`;
    const errId = `${id}-err`;
    return (
      <div className="flex flex-col gap-1">
        <label htmlFor={id}>
          {label}
          {required && <span aria-label="required">*</span>}
          {helpTooltip && <Tooltip content={helpTooltip} />}
        </label>
        {description && <p id={descId}>{description}</p>}
        <input
          ref={ref}
          id={id}
          aria-describedby={cn(description && descId, error && errId)}
          aria-invalid={!!error || undefined}
          {...inputProps}
        />
        {error && <p id={errId} role="alert">{error}</p>}
      </div>
    );
  }
);

// state/cells.ts
import { atom } from 'jotai';
import { atomFamily } from 'jotai/utils';
import { Parser } from 'hot-formula-parser';

interface Cell {
  raw: string; // user input, e.g., '=A1+B1' or '42'
  computed: number | string | null;
  error?: string;
  deps: string[]; // cell ids this cell depends on
}

// Each cell's raw value
export const cellRawAtom = atomFamily((cellId: string) =>
  atom('')
);

// Computed value depends on raw + dep values
export const cellComputedAtom = atomFamily((cellId: string) =>
  atom((get) => {
    const raw = get(cellRawAtom(cellId));
    if (!raw.startsWith('=')) return raw;
    // Parse formula and resolve dependencies
    const parser = new Parser();
    parser.on('callCellValue', (cellCoord, done) => {
      const depId = cellCoord.label;
      const depValue = get(cellComputedAtom(depId)); // dependency tracked by Jotai
      done(depValue);
    });
    const { result, error } = parser.parse(raw.slice(1));
    return error ? `#ERR: ${error}` : result;
  })
);

// components/Cell.tsx - isolated subscriber
import { useAtomValue, useSetAtom } from 'jotai';
import { cellRawAtom, cellComputedAtom } from '@/state/cells';
import { memo, useState, useRef, useEffect } from 'react';

interface CellProps {
  cellId: string;
}

export const Cell = memo(function Cell({ cellId }: CellProps) {
  const computed = useAtomValue(cellComputedAtom(cellId));
  const setRaw = useSetAtom(cellRawAtom(cellId));
  const [editing, setEditing] = useState(false);
  const [draft, setDraft] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (editing) inputRef.current?.focus();
  }, [editing]);

  if (editing) {
    return (
      <input
        ref={inputRef}
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onBlur={() => {
          setRaw(draft);
          setEditing(false);
        }}
        onKeyDown={(e) => {
          if (e.key === 'Enter') {
            setRaw(draft);
            setEditing(false);
          }
        }}
        className="w-full h-full px-1 outline-none"
      />
    );
  }

  return (
    <div
      onDoubleClick={() => {
        const raw = String(computed ?? '');
        setDraft(raw);
        setEditing(true);
      }}
      className="w-full h-full px-1 truncate"
    >
      {computed}
    </div>
  );
});

// components/Grid.tsx - virtualized grid
import { FixedSizeGrid } from 'react-window';

export function Grid({ rows, cols }: { rows: number; cols: number }) {
  return (
    <FixedSizeGrid
      columnCount={cols}
      columnWidth={100}
      rowCount={rows}
      rowHeight={28}
      width={Math.min(cols * 100, window.innerWidth - 40)}
      height={Math.min(rows * 28, window.innerHeight - 100)}
    >
      {({ rowIndex, columnIndex, style }) => {
        const cellId = `${String.fromCharCode(65 + columnIndex)}${rowIndex + 1}`;
        return (
          <div style={style} className="border-r border-b">
            <Cell cellId={cellId} />
          </div>
        );
      }}
    </FixedSizeGrid>
  );
}

// state/cells-signals.ts
import { signal, computed, Signal } from '@preact/signals-react';

const cellSignals = new Map<string, Signal<string>>();
const computedCache = new Map<string, ReturnType<typeof computed>>();

export function getCellRaw(cellId: string): Signal<string> {
  if (!cellSignals.has(cellId)) {
    cellSignals.set(cellId, signal(''));
  }
  return cellSignals.get(cellId)!;
}

export function getCellComputed(cellId: string) {
  if (!computedCache.has(cellId)) {
    computedCache.set(
      cellId,
      computed(() => {
        const raw = getCellRaw(cellId).value;
        if (!raw.startsWith('=')) return raw;
        // Formula parsing with dep resolution via getCellComputed reads
        return parseFormula(raw.slice(1));
      })
    );
  }
  return computedCache.get(cellId)!;
}

// components/Cell-signals.tsx
import { getCellComputed, getCellRaw } from '@/state/cells-signals';

export function CellSignal({ cellId }: { cellId: string }) {
  const computedSig = getCellComputed(cellId);
  // No subscription ceremony - read .value, signals tracks
  return <div>{computedSig.value}</div>;
}

// scripts/measure-compiler-perf.ts
import { chromium } from 'playwright';

const INTERACTIONS = [
  { name: 'open-modal', url: '/dashboard', action: 'click[role=button][name=Open]' },
  { name: 'type-in-form', url: '/settings', action: 'fill[name=email]:abc@example.com' },
  // ... 10 representative interactions
];

async function measure(buildVariant: 'with-compiler' | 'without-compiler') {
  const browser = await chromium.launch();
  const results: Record<string, number[]> = {};
  for (const interaction of INTERACTIONS) {
    const page = await browser.newPage();
    await page.goto(`http://localhost:3000${interaction.url}?variant=${buildVariant}`);
    const samples: number[] = [];
    for (let i = 0; i < 10; i++) {
      const start = await page.evaluate(() => performance.now());
      await page.evaluate((sel) => {
        // execute interaction
      }, interaction.action);
      await page.waitForLoadState('networkidle');
      const end = await page.evaluate(() => performance.now());
      samples.push(end - start);
    }
    results[interaction.name] = samples;
  }
  await browser.close();
  return results;
}

const withCompiler = await measure('with-compiler');
const withoutCompiler = await measure('without-compiler');

for (const [name, samplesWith] of Object.entries(withCompiler)) {
  const samplesWithout = withoutCompiler[name];
  const meanWith = samplesWith.reduce((a, b) => a + b, 0) / samplesWith.length;
  const meanWithout = samplesWithout.reduce((a, b) => a + b, 0) / samplesWithout.length;
  const improvement = ((meanWithout - meanWith) / meanWithout) * 100;
  console.log(`${name}: ${improvement.toFixed(1)}% improvement`);
}

