// Example fix for compiler-flagged impurity
// BEFORE (impure - sets state during render conditionally):
function BadComponent({ user }: { user: User | null }) {
  const [error, setError] = useState<string | null>(null);
  if (!user && !error) {
    setError('User required'); // setState during render!
  }
  return <div>{error}</div>;
}

// AFTER (effect or derived):
function GoodComponent({ user }: { user: User | null }) {
  const error = user ? null : 'User required'; // derived, not stored
  return <div>{error}</div>;
}

// Before/after for legacy useCallback (no change needed - leave as is)
function Existing({ onClick }: { onClick: (id: string) => void }) {
  const handleClick = useCallback((id: string) => onClick(id), [onClick]);
  return <Child onClick={handleClick} />;
}

// New code post-compiler enable - no useCallback needed:
function NewComponent({ onClick }: { onClick: (id: string) => void }) {
  const handleClick = (id: string) => onClick(id); // compiler auto-memoizes
  return <Child onClick={handleClick} />;
}

